final:
module RefModule(
	input clk,
	input reset_n,
	input load,
	input [7:0] data_in,
	output reg data_out);

reg [7:0] shift_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
	if (!reset_n)
		shift_reg <= 0;
	else if (load)
		shift_reg <= data_in;
	else
		shift_reg <= {shift_reg[6:0], 1'b0};

always @(shift_reg)
	data_out = shift_reg[7];

endmodule
